function ResultCard({ result }) {
  if (!result) return null;

  return (
    <div className="result-card">
      <h2>Prediction Results</h2>

      <div className="features">
        <p><strong>Length:</strong> {result.length_cm} cm</p>
        <p><strong>Thickness:</strong> {result.thickness_cm} cm</p>
        <p><strong>Perimeter:</strong> {result.perimeter_cm} cm</p>
        <p><strong>Area:</strong> {result.area_cm2} cm²</p>
        <p><strong>Volume Proxy:</strong> {result.volume_proxy_cm3} cm³</p>
      </div>

      <hr />

      <h3>
        Predicted Weight: {result.predicted_weight_g} g
      </h3>
    </div>
  );
}

export default ResultCard;
